import java.util.concurrent.CompletableFuture;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;

public class CompletableFutureExample {

    public static void main(String[] args) {

        // ExecutorService for offloading tasks to a separate thread pool
        ExecutorService executor = Executors.newFixedThreadPool(4);

        // Example: Asynchronously compute the square of a number
        CompletableFuture<Integer> future = CompletableFuture.supplyAsync(() -> {
            int number = 10;
            return number * number;
        }, executor);

        // Handle the result when it's ready
        future.thenAccept(result -> System.out.println("The square of 10 is: " + result));

        // Shut down the executor service
        executor.shutdown();
    }
}
```

This example demonstrates how to use `CompletableFuture` to compute the square of a number asynchronously. The computation is offloaded to a separate thread pool to ensure the main thread remains free to perform other tasks.

